const charge = await stripe.charges.create({
  amount: 1000,
  currency: 'usd',
  idempotency_key: \`order-\${orderId}\`,
});

// Check DLQ depth every minute
setInterval(async () => {
  const waiting = await dlq.getWaitingCount();
  if (waiting > 100) {
    await alertOps({ type: 'dlq_overflow', count: waiting });
  }
}, 60000);

