# Node.js Cluster Module: Multi-Core Utilization

## Introduction

Node.js runs JavaScript on a single thread. On a modern 8-core server, a single Node.js process uses only 12.5% of available CPU. The `cluster` module lets you fork multiple worker processes that share the same server port, utilizing all available CPU cores.

## The Problem

```
Single Process:
┌────────────────────────────────────────┐
│  8-Core Server                         │
│  ┌──────┐                              │
│  │Node.js│  Core 1: 100% busy          │
│  │Process│  Core 2-8: IDLE             │
│  └──────┘                              │
│  Only 1/8 of CPU utilized             │
└────────────────────────────────────────┘

With Cluster Module:
┌────────────────────────────────────────┐
│  8-Core Server                         │
│  ┌──────┐ ┌──────┐ ┌──────┐ ┌──────┐  │
│  │Worker│ │Worker│ │Worker│ │Worker│  │
│  │  1   │ │  2   │ │  3   │ │  4   │  │
│  └──────┘ └──────┘ └──────┘ └──────┘  │
│  ┌──────┐ ┌──────┐ ┌──────┐ ┌──────┐  │
│  │Worker│ │Worker│ │Worker│ │  Pri- │  │
│  │  5   │ │  6   │ │  7   │ │ mary │  │
│  └──────┘ └──────┘ └──────┘ └──────┘  │
│  All 8 cores utilized                 │
└────────────────────────────────────────┘
```

## Basic Cluster Setup

```javascript
import cluster from 'node:cluster';
import os from 'node:os';
import express from 'express';

const numCPUs = os.cpus().length;

if (cluster.isPrimary) {
  console.log(`Primary process ${process.pid} starting ${numCPUs} workers`);

  // Fork workers
  for (let i = 0; i < numCPUs; i++) {
    cluster.fork();
  }

  // Handle worker exit
  cluster.on('exit', (worker, code, signal) => {
    console.log(`Worker ${worker.process.pid} died (code: ${code}, signal: ${signal})`);
    // Replace dead worker
    console.log('Starting a new worker...');
    cluster.fork();
  });

  // Monitor workers
  cluster.on('online', (worker) => {
    console.log(`Worker ${worker.process.pid} is online`);
  });

} else {
  // Workers share the same port
  const app = express();

  app.get('/', (req, res) => {
    res.json({
      pid: process.pid,
      uptime: process.uptime(),
    });
  });

  app.get('/heavy', (req, res) => {
    // CPU-intensive work — only blocks THIS worker
    let sum = 0;
    for (let i = 0; i < 1e8; i++) sum += i;
    res.json({ result: sum, pid: process.pid });
  });

  app.listen(3000, () => {
    console.log(`Worker ${process.pid} listening on port 3000`);
  });
}
```

## Graceful Shutdown and Zero-Downtime Restart

```javascript
if (cluster.isPrimary) {
  const workers = [];

  function forkWorker() {
    const worker = cluster.fork();
    workers.push(worker);
    return worker;
  }

  // Initial fork
  for (let i = 0; i < numCPUs; i++) {
    forkWorker();
  }

  // Zero-downtime restart
  process.on('SIGUSR2', async () => {
    console.log('Received SIGUSR2 - starting zero-downtime restart');

    const currentWorkers = [...Object.values(cluster.workers)];

    for (const worker of currentWorkers) {
      // Start new worker
      const newWorker = forkWorker();

      // Wait for new worker to be ready
      await new Promise((resolve) => {
        newWorker.on('listening', resolve);
      });

      // Gracefully shut down old worker
      worker.send('shutdown');
      worker.disconnect();

      await new Promise((resolve) => {
        const timeout = setTimeout(() => {
          worker.kill('SIGKILL');
          resolve();
        }, 10000); // Force kill after 10s

        worker.on('exit', () => {
          clearTimeout(timeout);
          resolve();
        });
      });
    }

    console.log('Zero-downtime restart complete');
  });

  // Replace crashed workers
  cluster.on('exit', (worker, code, signal) => {
    if (code !== 0 && !worker.exitedAfterDisconnect) {
      console.log(`Worker ${worker.process.pid} crashed. Restarting...`);
      forkWorker();
    }
  });

} else {
  const app = express();
  const server = app.listen(3000);

  // Handle graceful shutdown
  process.on('message', (msg) => {
    if (msg === 'shutdown') {
      console.log(`Worker ${process.pid}: shutting down gracefully`);

      // Stop accepting new connections
      server.close(() => {
        console.log(`Worker ${process.pid}: all connections closed`);
        process.exit(0);
      });

      // Force close after timeout
      setTimeout(() => {
        console.log(`Worker ${process.pid}: forcing shutdown`);
        process.exit(1);
      }, 5000);
    }
  });
}
```

## Inter-Process Communication (IPC)

Workers can communicate with the primary process via IPC:

```javascript
if (cluster.isPrimary) {
  // Aggregate metrics from all workers
  const metrics = { totalRequests: 0, errors: 0 };

  cluster.on('message', (worker, message) => {
    if (message.type === 'metric') {
      metrics.totalRequests += message.requests || 0;
      metrics.errors += message.errors || 0;
    }
  });

  // Broadcast to all workers
  function broadcast(message) {
    for (const worker of Object.values(cluster.workers)) {
      worker.send(message);
    }
  }

  // Periodically request metrics
  setInterval(() => {
    broadcast({ type: 'report-metrics' });
  }, 10000);

  // Expose metrics endpoint on a different port
  const adminApp = express();
  adminApp.get('/metrics', (req, res) => {
    res.json({
      ...metrics,
      workers: Object.values(cluster.workers).map(w => ({
        pid: w.process.pid,
        state: w.state,
      })),
    });
  });
  adminApp.listen(3001);

} else {
  let requestCount = 0;
  let errorCount = 0;

  const app = express();

  app.use((req, res, next) => {
    requestCount++;
    res.on('finish', () => {
      if (res.statusCode >= 500) errorCount++;
    });
    next();
  });

  // Report metrics when asked
  process.on('message', (msg) => {
    if (msg.type === 'report-metrics') {
      process.send({
        type: 'metric',
        requests: requestCount,
        errors: errorCount,
      });
      requestCount = 0;
      errorCount = 0;
    }
  });
}
```

## PM2: Cluster Management Made Easy

PM2 provides cluster mode without writing cluster code:

```javascript
// ecosystem.config.js
module.exports = {
  apps: [{
    name: 'api',
    script: './dist/server.js',
    instances: 'max',        // Use all CPU cores
    exec_mode: 'cluster',    // Enable cluster mode
    max_memory_restart: '500M',
    env: {
      NODE_ENV: 'production',
      PORT: 3000,
    },
    // Graceful shutdown
    kill_timeout: 5000,
    listen_timeout: 10000,
    // Zero-downtime reload
    wait_ready: true,
    // Logging
    error_file: './logs/error.log',
    out_file: './logs/out.log',
    merge_logs: true,
  }],
};
```

```bash
# Start in cluster mode
pm2 start ecosystem.config.js

# Zero-downtime reload
pm2 reload api

# Scale up/down
pm2 scale api 4   # Set to 4 instances
pm2 scale api +2  # Add 2 more instances
```

For PM2 graceful shutdown:

```javascript
// In your app
const server = app.listen(3000, () => {
  // Tell PM2 we're ready
  process.send?.('ready');
});

process.on('SIGINT', () => {
  server.close(() => {
    process.exit(0);
  });
});
```

## Shared State Caveat

Each worker has its own memory space. In-memory state is NOT shared:

```javascript
// BAD: This counter is per-worker, not global
let requestCount = 0;
app.use((req, res, next) => {
  requestCount++; // Only counts requests for THIS worker
  next();
});

// GOOD: Use Redis for shared state
app.use(async (req, res, next) => {
  await redis.incr('global:request-count');
  next();
});
```

## Common Pitfalls

1. **Assuming shared memory**: Each worker is a separate process. Use Redis or IPC for shared state.
2. **Not handling worker crashes**: Without restart logic, workers silently die and reduce capacity.
3. **Running more workers than CPU cores**: Extra workers cause context switching overhead. Match worker count to core count.
4. **Not implementing graceful shutdown**: Killing workers immediately drops in-flight requests. Always drain connections first.

## Summary

The cluster module enables Node.js to utilize all CPU cores by forking worker processes that share a server port. The primary process manages workers, handles restarts, and can coordinate via IPC. PM2 provides production-ready cluster management with zero-downtime reloads. Remember that each worker has isolated memory — use Redis for shared state.

8.5.2.body:
# Worker Threads: CPU-Bound Tasks in Node.js

## Introduction

While the cluster module creates separate processes for handling concurrent requests, `worker_threads` creates threads within a single process for offloading CPU-intensive work. This is the correct solution when you need to run expensive computations (encryption, image processing, data parsing) without blocking the main event loop.

## Cluster vs Worker Threads

```
Cluster Module:                    Worker Threads:
- Separate processes               - Threads in same process
- Each has own V8 heap              - Can share memory (SharedArrayBuffer)
- IPC for communication             - MessagePort for communication
- For scaling HTTP servers           - For CPU-intensive tasks
- Higher memory overhead             - Lower memory overhead

Use cluster for:                   Use worker_threads for:
  Multiple HTTP listeners            Image/video processing
  Multi-core HTTP serving             JSON parsing large files
  Process isolation                   Cryptographic operations
                                      Data compression
                                      Machine learning inference
```

## Basic Worker Thread

```javascript
// main.js
import { Worker } from 'node:worker_threads';

function runWorker(data) {
  return new Promise((resolve, reject) => {
    const worker = new Worker('./worker.js', {
      workerData: data,
    });

    worker.on('message', resolve);
    worker.on('error', reject);
    worker.on('exit', (code) => {
      if (code !== 0) {
        reject(new Error(`Worker exited with code ${code}`));
      }
    });
  });
}

// Usage in Express
app.post('/api/process-data', async (req, res) => {
  try {
    const result = await runWorker(req.body);
    res.json(result);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});
```

```javascript
// worker.js
import { workerData, parentPort } from 'node:worker_threads';

function expensiveComputation(data) {
  // Simulate CPU-intensive work
  let result = 0;
  for (let i = 0; i < data.iterations; i++) {
    result += Math.sqrt(i) * Math.sin(i);
  }
  return result;
}

const result = expensiveComputation(workerData);
parentPort.postMessage({ result, processedAt: new Date().toISOString() });
```

## Worker Thread Pool

Creating a new thread per request is expensive. Use a pool:

```javascript
import { Worker } from 'node:worker_threads';
import os from 'node:os';

class WorkerPool {
  constructor(workerPath, poolSize = os.cpus().length) {
    this.workerPath = workerPath;
    this.poolSize = poolSize;
    this.workers = [];
    this.freeWorkers = [];
    this.taskQueue = [];

    for (let i = 0; i < poolSize; i++) {
      this._addWorker();
    }
  }

  _addWorker() {
    const worker = new Worker(this.workerPath);

    worker.on('message', (result) => {
      // Resolve the pending task
      worker._resolve(result);
      worker._resolve = null;
      worker._reject = null;

      // Check for queued tasks
      if (this.taskQueue.length > 0) {
        const { data, resolve, reject } = this.taskQueue.shift();
        this._runTask(worker, data, resolve, reject);
      } else {
        this.freeWorkers.push(worker);
      }
    });

    worker.on('error', (err) => {
      if (worker._reject) {
        worker._reject(err);
      }
      // Replace dead worker
      this.workers = this.workers.filter(w => w !== worker);
      this._addWorker();
    });

    this.workers.push(worker);
    this.freeWorkers.push(worker);
  }

  _runTask(worker, data, resolve, reject) {
    worker._resolve = resolve;
    worker._reject = reject;
    worker.postMessage(data);
  }

  execute(data) {
    return new Promise((resolve, reject) => {
      const freeWorker = this.freeWorkers.pop();

      if (freeWorker) {
        this._runTask(freeWorker, data, resolve, reject);
      } else {
        this.taskQueue.push({ data, resolve, reject });
      }
    });
  }

  async destroy() {
    for (const worker of this.workers) {
      await worker.terminate();
    }
  }

  get stats() {
    return {
      totalWorkers: this.workers.length,
      freeWorkers: this.freeWorkers.length,
      busyWorkers: this.workers.length - this.freeWorkers.length,
      queuedTasks: this.taskQueue.length,
    };
  }
}

// Usage
const pool = new WorkerPool('./hash-worker.js', 4);

app.post('/api/hash', async (req, res) => {
  const result = await pool.execute({
    algorithm: 'bcrypt',
    data: req.body.password,
    rounds: 12,
  });
  res.json(result);
});

app.get('/api/pool-stats', (req, res) => {
  res.json(pool.stats);
});

// Cleanup on shutdown
process.on('SIGTERM', () => pool.destroy());
```

## Shared Memory with SharedArrayBuffer

For high-performance scenarios, threads can share memory:

```javascript
// main.js
import { Worker } from 'node:worker_threads';

// Create shared buffer
const sharedBuffer = new SharedArrayBuffer(1024 * 1024); // 1MB
const sharedArray = new Int32Array(sharedBuffer);

// Initialize data
for (let i = 0; i < sharedArray.length; i++) {
  sharedArray[i] = i;
}

// Spawn workers that operate on shared memory
const workers = [];
const chunkSize = Math.ceil(sharedArray.length / 4);

for (let i = 0; i < 4; i++) {
  const worker = new Worker('./sum-worker.js', {
    workerData: {
      sharedBuffer,
      start: i * chunkSize,
      end: Math.min((i + 1) * chunkSize, sharedArray.length),
    },
  });
  workers.push(new Promise(resolve => worker.on('message', resolve)));
}

const partialSums = await Promise.all(workers);
const totalSum = partialSums.reduce((a, b) => a + b, 0);
console.log('Total sum:', totalSum);
```

```javascript
// sum-worker.js
import { workerData, parentPort } from 'node:worker_threads';

const { sharedBuffer, start, end } = workerData;
const arr = new Int32Array(sharedBuffer);

let sum = 0;
for (let i = start; i < end; i++) {
  sum += arr[i];
}

parentPort.postMessage(sum);
```

## Using Atomics for Thread-Safe Operations

```javascript
import { Worker, isMainThread, workerData, parentPort } from 'node:worker_threads';

if (isMainThread) {
  const sharedBuffer = new SharedArrayBuffer(4);
  const counter = new Int32Array(sharedBuffer);

  const workers = Array.from({ length: 4 }, () =>
    new Worker(import.meta.filename, {
      workerData: { sharedBuffer, iterations: 100000 },
    })
  );

  await Promise.all(workers.map(w => new Promise(r => w.on('exit', r))));

  console.log('Counter value:', counter[0]);
  // Should be exactly 400000 with Atomics
  // Would be less without Atomics due to race conditions
} else {
  const counter = new Int32Array(workerData.sharedBuffer);

  for (let i = 0; i < workerData.iterations; i++) {
    Atomics.add(counter, 0, 1); // Thread-safe increment
  }
}
```

## Real-World Use Cases

### Image Processing

```javascript
// image-worker.js
import { parentPort } from 'node:worker_threads';
import sharp from 'sharp';

parentPort.on('message', async ({ imagePath, operations }) => {
  let pipeline = sharp(imagePath);

  for (const op of operations) {
    switch (op.type) {
      case 'resize':
        pipeline = pipeline.resize(op.width, op.height);
        break;
      case 'format':
        pipeline = pipeline.toFormat(op.format, { quality: op.quality });
        break;
      case 'blur':
        pipeline = pipeline.blur(op.sigma);
        break;
    }
  }

  const buffer = await pipeline.toBuffer();
  parentPort.postMessage({ buffer, size: buffer.length });
});
```

### JSON Parsing of Large Files

```javascript
// parse-worker.js
import { parentPort } from 'node:worker_threads';
import { createReadStream } from 'node:fs';
import { parser } from 'stream-json';
import { streamArray } from 'stream-json/streamers/StreamArray.js';

parentPort.on('message', async ({ filePath, filter }) => {
  const results = [];
  const pipeline = createReadStream(filePath)
    .pipe(parser())
    .pipe(streamArray());

  for await (const { value } of pipeline) {
    if (matchesFilter(value, filter)) {
      results.push(value);
    }
  }

  parentPort.postMessage({ count: results.length, results });
});
```

## Piscina: Production Worker Pool

```javascript
import Piscina from 'piscina';

const pool = new Piscina({
  filename: './worker.js',
  minThreads: 2,
  maxThreads: 8,
  idleTimeout: 30000,
});

app.post('/api/process', async (req, res) => {
  const result = await pool.run(req.body);
  res.json(result);
});

// worker.js (exports a function)
export default function processData(data) {
  // CPU-intensive work
  return { processed: true, result: heavyComputation(data) };
}
```

## Common Pitfalls

1. **Using worker threads for I/O**: Worker threads are for CPU-bound work. I/O is already non-blocking via the event loop. Don't use workers for database queries or HTTP requests.
2. **Transferring large data via postMessage**: Each postMessage serializes and copies data. For large data, use SharedArrayBuffer or transferable objects.
3. **Not pooling workers**: Creating a new worker per request is expensive (~50ms startup). Always use a pool.
4. **Deadlocks with Atomics.wait**: On the main thread, Atomics.wait blocks the event loop. Only use it in worker threads.

## Summary

Worker threads enable CPU-intensive operations in Node.js without blocking the event loop. Use them for image processing, data parsing, cryptography, and other compute-heavy tasks. Always use a worker pool (custom or Piscina) to amortize thread creation costs. Use SharedArrayBuffer for zero-copy data sharing between threads, and Atomics for thread-safe operations.

