# EventEmitter Patterns and Domain Events

## Introduction

Before reaching for Kafka or RabbitMQ, Node.js provides a built-in pub/sub mechanism: the EventEmitter. For in-process event-driven architecture, domain events with EventEmitter provide loose coupling between modules without the infrastructure overhead of an external message broker. This pattern is the foundation of domain-driven design in Node.js.

## Node.js EventEmitter Basics

```javascript
import { EventEmitter } from 'node:events';

const emitter = new EventEmitter();

// Subscribe
emitter.on('user.created', (user) => {
  console.log('Send welcome email to:', user.email);
});

emitter.on('user.created', (user) => {
  console.log('Initialize user preferences for:', user.id);
});

// Publish
emitter.emit('user.created', { id: 1, email: 'alice@example.com' });
```

## Typed Event Bus

```javascript
// Type-safe event bus with TypeScript
class TypedEventBus {
  constructor() {
    this.emitter = new EventEmitter();
    this.emitter.setMaxListeners(50);
  }

  on(event, handler) {
    this.emitter.on(event, handler);
    return () => this.emitter.off(event, handler); // Return unsubscribe fn
  }

  once(event, handler) {
    this.emitter.once(event, handler);
  }

  emit(event, data) {
    this.emitter.emit(event, data);
  }

  async emitAsync(event, data) {
    const listeners = this.emitter.listeners(event);
    await Promise.all(
      listeners.map(listener => listener(data))
    );
  }

  removeAllListeners(event) {
    this.emitter.removeAllListeners(event);
  }
}

// Singleton event bus
export const eventBus = new TypedEventBus();
```

## Domain Events Pattern

Domain events represent something meaningful that happened in the business domain:

```javascript
// Define domain events
class DomainEvent {
  constructor(type, data) {
    this.type = type;
    this.data = data;
    this.timestamp = new Date();
    this.id = crypto.randomUUID();
  }
}

class OrderCreatedEvent extends DomainEvent {
  constructor(order) {
    super('order.created', {
      orderId: order.id,
      userId: order.userId,
      items: order.items,
      total: order.total,
    });
  }
}

class OrderPaidEvent extends DomainEvent {
  constructor(orderId, paymentId) {
    super('order.paid', { orderId, paymentId });
  }
}

class UserRegisteredEvent extends DomainEvent {
  constructor(user) {
    super('user.registered', {
      userId: user.id,
      email: user.email,
      name: user.name,
    });
  }
}
```

## Event-Driven Service Layer

```javascript
// Order service emits events after business operations
class OrderService {
  constructor(orderRepo, eventBus) {
    this.orderRepo = orderRepo;
    this.eventBus = eventBus;
  }

  async createOrder(userId, items) {
    const order = await this.orderRepo.create({ userId, items });

    // Emit domain event
    await this.eventBus.emitAsync('order.created', new OrderCreatedEvent(order));

    return order;
  }

  async payOrder(orderId, paymentDetails) {
    const order = await this.orderRepo.findById(orderId);
    const payment = await this.paymentGateway.charge(paymentDetails);

    await this.orderRepo.update(orderId, { status: 'PAID' });

    await this.eventBus.emitAsync('order.paid', new OrderPaidEvent(orderId, payment.id));

    return order;
  }
}

// Handlers are registered at module initialization
class EmailHandler {
  constructor(eventBus, emailService) {
    // Register event handlers
    eventBus.on('order.created', this.onOrderCreated.bind(this));
    eventBus.on('order.paid', this.onOrderPaid.bind(this));
    eventBus.on('user.registered', this.onUserRegistered.bind(this));
  }

  async onOrderCreated(event) {
    await this.emailService.send({
      to: event.data.userId,
      template: 'order-confirmation',
      data: { orderId: event.data.orderId, total: event.data.total },
    });
  }

  async onOrderPaid(event) {
    await this.emailService.send({
      to: event.data.userId,
      template: 'payment-receipt',
      data: { orderId: event.data.orderId },
    });
  }

  async onUserRegistered(event) {
    await this.emailService.send({
      to: event.data.email,
      template: 'welcome',
      data: { name: event.data.name },
    });
  }
}

class AnalyticsHandler {
  constructor(eventBus, analyticsService) {
    eventBus.on('order.created', this.trackOrderCreated.bind(this));
    eventBus.on('user.registered', this.trackUserRegistered.bind(this));
  }

  async trackOrderCreated(event) {
    await this.analyticsService.track('order_created', {
      orderId: event.data.orderId,
      total: event.data.total,
    });
  }

  async trackUserRegistered(event) {
    await this.analyticsService.track('user_registered', {
      userId: event.data.userId,
    });
  }
}
```

## NestJS Event-Driven with CQRS Module

```javascript
import { EventBus, EventsHandler, IEventHandler } from '@nestjs/cqrs';

// Event
class OrderCreatedEvent {
  constructor(orderId, userId, total) {
    this.orderId = orderId;
    this.userId = userId;
    this.total = total;
  }
}

// Handler 1: Send email
@EventsHandler(OrderCreatedEvent)
class OrderCreatedEmailHandler {
  constructor(private emailService: EmailService) {}

  async handle(event) {
    await this.emailService.sendOrderConfirmation(event.userId, event.orderId);
  }
}

// Handler 2: Update analytics
@EventsHandler(OrderCreatedEvent)
class OrderCreatedAnalyticsHandler {
  constructor(private analyticsService: AnalyticsService) {}

  async handle(event) {
    await this.analyticsService.track('order_created', {
      orderId: event.orderId,
      total: event.total,
    });
  }
}

// Service publishes event
@Injectable()
class OrderService {
  constructor(private eventBus: EventBus) {}

  async createOrder(data) {
    const order = await this.orderRepo.create(data);
    this.eventBus.publish(new OrderCreatedEvent(order.id, data.userId, order.total));
    return order;
  }
}
```

## Bridging In-Process Events to External Systems

```javascript
// Bridge: EventEmitter events → Kafka/Redis for cross-service communication
class EventBridge {
  constructor(eventBus, kafkaProducer, redis) {
    this.eventBus = eventBus;
    this.producer = kafkaProducer;
    this.redis = redis;

    // Bridge specific events to Kafka
    this.bridgeToKafka('order.created', 'orders');
    this.bridgeToKafka('order.paid', 'orders');
    this.bridgeToKafka('user.registered', 'user-events');

    // Bridge to Redis pub/sub for real-time notifications
    this.bridgeToRedis('order.status.changed');
  }

  bridgeToKafka(eventType, topic) {
    this.eventBus.on(eventType, async (event) => {
      await this.producer.send({
        topic,
        messages: [{
          key: event.data.orderId || event.data.userId,
          value: JSON.stringify(event),
          headers: { 'event-type': eventType },
        }],
      });
    });
  }

  bridgeToRedis(eventType) {
    this.eventBus.on(eventType, async (event) => {
      await this.redis.publish(eventType, JSON.stringify(event));
    });
  }
}
```

## Error Handling in Event Handlers

```javascript
class ResilientEventBus extends TypedEventBus {
  async emitAsync(event, data) {
    const listeners = this.emitter.listeners(event);

    const results = await Promise.allSettled(
      listeners.map(listener => listener(data))
    );

    // Log failures but don't fail the main operation
    const failures = results.filter(r => r.status === 'rejected');
    if (failures.length > 0) {
      console.error(`${failures.length} handler(s) failed for event '${event}':`,
        failures.map(f => f.reason.message)
      );
    }

    return {
      total: results.length,
      succeeded: results.filter(r => r.status === 'fulfilled').length,
      failed: failures.length,
    };
  }
}
```

## Common Pitfalls

1. **Event handler errors crashing the emitter**: Use `Promise.allSettled` in async handlers. Unhandled errors in EventEmitter crash the process.
2. **Memory leaks from unremoved listeners**: Always remove listeners when modules are destroyed. Set max listeners appropriately.
3. **Circular event chains**: Event A triggers handler that emits Event B, which triggers handler that emits Event A. Add cycle detection.
4. **Assuming delivery order**: EventEmitter delivers synchronously in registration order, but async handlers may complete in any order.

## Summary

EventEmitter provides lightweight in-process pub/sub for domain events within a Node.js application. Domain events decouple business logic from side effects (emails, analytics, notifications). For cross-service communication, bridge in-process events to Kafka or Redis. Use NestJS CQRS module for structured event handling in NestJS applications. Always handle errors in event handlers gracefully to prevent one failed handler from affecting others.

8.8.1.body:
# CAP Theorem and Consistency Models

## Introduction

The CAP theorem is the foundational concept for understanding trade-offs in distributed systems. It states that a distributed data store can provide only two of three guarantees: Consistency, Availability, and Partition Tolerance. Since network partitions are inevitable in distributed systems, you must choose between consistency and availability.

## The CAP Theorem

```
        Consistency (C)
           /\
          /  \
         /    \
        / CP   \   CA (theoretical only
       /  sys   \   in practice - no
      /    /    \  partition tolerance)
     /            \
    /      AP      \
   /      sys       \
  /_________________ \
Availability (A)    Partition
                    Tolerance (P)

CP Systems: MongoDB, HBase, Redis (in some modes)
  → Strong consistency, may become unavailable during partition

AP Systems: Cassandra, DynamoDB, CouchDB
  → Always available, may return stale data during partition

CA Systems: Single-node PostgreSQL (not distributed)
  → Not applicable to distributed systems
```

## Understanding Each Property

### Consistency

Every read receives the most recent write or an error.

```
Consistent System:
  T0: Client A writes x = 5 to Node 1
  T1: Client B reads x from Node 2
  T2: Client B gets x = 5 (or error if not yet replicated)

Inconsistent System:
  T0: Client A writes x = 5 to Node 1
  T1: Client B reads x from Node 2
  T2: Client B gets x = 3 (stale value!)
```

### Availability

Every request receives a non-error response, without guarantee that it contains the most recent write.

### Partition Tolerance

The system continues to operate despite network partitions between nodes.

```
Network Partition:
┌──────────┐         X         ┌──────────┐
│  Node 1  │ ─ ─ ─ ─ X ─ ─ ─ ─│  Node 2  │
│  (x = 5) │    network        │  (x = 3) │
└──────────┘     broken         └──────────┘

CP choice: Node 2 refuses reads (unavailable) until partition heals
AP choice: Node 2 returns x = 3 (stale but available)
```

## Consistency Models

### Strong Consistency (Linearizability)

After a write completes, all subsequent reads reflect that write. This is what single-database applications provide.

```javascript
// Strong consistency with PostgreSQL transaction
async function transferMoney(fromId, toId, amount) {
  return prisma.$transaction(async (tx) => {
    const from = await tx.account.findUnique({
      where: { id: fromId },
    });

    if (from.balance < amount) throw new Error('Insufficient funds');

    await tx.account.update({
      where: { id: fromId },
      data: { balance: { decrement: amount } },
    });

    await tx.account.update({
      where: { id: toId },
      data: { balance: { increment: amount } },
    });
    // After COMMIT, all reads see the updated balances
  });
}
```

### Eventual Consistency

If no new updates are made, eventually all reads will return the last updated value. There is a window where reads may return stale data.

```javascript
// Eventual consistency with cache
async function updateUserProfile(userId, data) {
  // Write to primary DB
  const user = await primaryDB.user.update({
    where: { id: userId },
    data,
  });

  // Cache update (eventually consistent)
  await redis.setex(`user:${userId}`, 3600, JSON.stringify(user));

  // Replica will eventually get the update
  // Reads from replica may return stale data for a few ms

  return user;
}

// Read may return stale data
async function getUserProfile(userId) {
  // Check cache (may be stale)
  const cached = await redis.get(`user:${userId}`);
  if (cached) return JSON.parse(cached);

  // Read from replica (may be slightly behind primary)
  return replicaDB.user.findUnique({ where: { id: userId } });
}
```

### Causal Consistency

Preserves the order of causally related operations, but allows concurrent operations to be seen in different orders.

```javascript
// Causal consistency example
// If User A posts a message, then replies to it,
// all readers must see the post before the reply.

class CausallyConsistentStore {
  constructor(redis) {
    this.redis = redis;
  }

  async write(key, value, causalDependencies = []) {
    const version = Date.now();

    // Wait for causal dependencies to be visible
    for (const dep of causalDependencies) {
      await this.waitForVersion(dep.key, dep.version);
    }

    await this.redis.hset(`data:${key}`, 'value', JSON.stringify(value), 'version', version);
    return version;
  }

  async read(key) {
    const data = await this.redis.hgetall(`data:${key}`);
    return {
      value: JSON.parse(data.value),
      version: parseInt(data.version),
    };
  }

  async waitForVersion(key, minVersion, timeoutMs = 5000) {
    const start = Date.now();
    while (Date.now() - start < timeoutMs) {
      const data = await this.redis.hget(`data:${key}`, 'version');
      if (parseInt(data) >= minVersion) return;
      await new Promise(r => setTimeout(r, 50));
    }
    throw new Error(`Timeout waiting for ${key} version ${minVersion}`);
  }
}
```

### Read-Your-Writes Consistency

A user always sees their own writes, but may see stale data from other users.

```javascript
// Read-your-writes with version tracking
class ReadYourWritesProxy {
  constructor(primaryDB, replicaDB, redis) {
    this.primaryDB = primaryDB;
    this.replicaDB = replicaDB;
    this.redis = redis;
  }

  async write(userId, table, data) {
    const result = await this.primaryDB[table].update(data);

    // Track user's last write timestamp
    await this.redis.setex(
      `last_write:${userId}`,
      30, // 30 second window
      Date.now().toString()
    );

    return result;
  }

  async read(userId, table, query) {
    const lastWrite = await this.redis.get(`last_write:${userId}`);

    if (lastWrite && Date.now() - parseInt(lastWrite) < 5000) {
      // User wrote recently — read from primary for freshness
      return this.primaryDB[table].findMany(query);
    }

    // No recent writes — safe to read from replica
    return this.replicaDB[table].findMany(query);
  }
}
```

## Practical CAP Trade-offs

```
┌──────────────────────────────────────────────────────────────┐
│ Use Case                    │ Consistency Model              │
├─────────────────────────────┼────────────────────────────────┤
│ Bank account balance        │ Strong (ACID transactions)     │
│ Shopping cart               │ Eventual (AP, merge conflicts) │
│ User profile                │ Read-your-writes               │
│ Social media feed           │ Eventual (seconds of lag OK)   │
│ Inventory count             │ Strong for decrements          │
│ Analytics dashboard         │ Eventual (minutes of lag OK)   │
│ Distributed counter (likes) │ Eventual (with CRDT or merge)  │
│ Chat messages               │ Causal (order matters)         │
└──────────────────────────────────────────────────────────────┘
```

## PACELC Theorem

An extension of CAP that also considers latency:

```
If Partition:
  Choose Availability or Consistency (PA or PC)
Else (normal operation):
  Choose Latency or Consistency (EL or EC)

PACELC Classification:
  DynamoDB: PA/EL (always available, low latency, eventual consistency)
  PostgreSQL: PC/EC (consistent, higher latency for distributed writes)
  MongoDB: PA/EC (available during partition, consistent normally)
```

## Common Pitfalls

1. **Assuming strong consistency everywhere**: Many systems don't need it. Eventual consistency with 100ms lag is fine for most read workloads.
2. **Ignoring partition scenarios**: Test what happens when the network between your app and database breaks. Does your system fail gracefully?
3. **Not documenting consistency guarantees**: Your API consumers need to know if a read might return stale data after a write.
4. **Trying to have all three**: Every distributed system must sacrifice something. Understand and accept the trade-offs.

## Summary

The CAP theorem forces a choice between consistency and availability during network partitions. Most real-world systems choose eventual consistency for reads (AP) while maintaining strong consistency for critical writes. Understanding consistency models (strong, eventual, causal, read-your-writes) lets you make informed trade-offs. Choose the consistency model based on the business requirement of each operation, not as a system-wide policy.

8.8.2.body:
# Distributed Consensus: Raft and Paxos

## Introduction

Distributed consensus is the problem of getting multiple nodes in a distributed system to agree on a value. This is fundamental to leader election, configuration management, and replicated state machines. Raft and Paxos are the two most important consensus algorithms.

## Why Consensus?

```
Problem: Who is the leader?

Node 1: "I'm the leader!"     ← Split brain
Node 2: "I'm the leader!"     ← Both accept writes
Node 3: "Who's the leader?"   ← Confusion

Solution: Consensus algorithm ensures
  ONE leader is elected and ALL nodes agree
```

Without consensus, distributed systems face:
- **Split brain**: Multiple nodes think they are the leader
- **Data loss**: Conflicting writes on different "leaders"
- **Inconsistency**: Nodes diverge and cannot reconcile

## Raft Consensus Algorithm

Raft was designed to be understandable. It breaks consensus into three sub-problems: leader election, log replication, and safety.

### Raft Node States

```
┌──────────┐    timeout     ┌────────────┐   wins election  ┌──────────┐
│ Follower │───────────────>│ Candidate  │────────────────>│  Leader  │
│          │                │            │                  │          │
│          │<───────────────│            │<─────────────────│          │
│          │  discovers     │            │  discovers       │          │
│          │  current       │            │  higher term     │          │
│          │  leader        │            │  leader          │          │
└──────────┘                └────────────┘                  └──────────┘
```

### Leader Election

```
Term 1: Node 1 is leader
  Node 1 (Leader) ──heartbeat──> Node 2 (Follower)
  Node 1 (Leader) ──heartbeat──> Node 3 (Follower)

Node 1 crashes! Heartbeat stops.

Term 2: Election
  Node 2: "Timeout! No heartbeat. Starting election for Term 2"
  Node 2 ──RequestVote──> Node 3: "Vote for me?"
  Node 3: "OK, you have my vote"
  Node 2: "I have 2/3 votes (majority). I am the new leader!"

Term 2: Node 2 is leader
  Node 2 (Leader) ──heartbeat──> Node 3 (Follower)
  (Node 1 is down)

Node 1 comes back:
  Node 1: "I was leader of Term 1"
  Node 2: "I'm leader of Term 2 (higher term)"
  Node 1: "OK, I'll be a follower"
```

### Simplified Raft Implementation (Educational)

```javascript
class RaftNode {
  constructor(id, peers) {
    this.id = id;
    this.peers = peers; // Other node URLs
    this.state = 'follower'; // follower, candidate, leader
    this.currentTerm = 0;
    this.votedFor = null;
    this.log = [];
    this.commitIndex = 0;

    // Timeouts
    this.electionTimeout = this._randomTimeout(150, 300);
    this.heartbeatInterval = 50;

    this.resetElectionTimer();
  }

  _randomTimeout(min, max) {
    return min + Math.random() * (max - min);
  }

  resetElectionTimer() {
    clearTimeout(this.electionTimer);
    this.electionTimer = setTimeout(
      () => this.startElection(),
      this.electionTimeout
    );
  }

  async startElection() {
    this.state = 'candidate';
    this.currentTerm++;
    this.votedFor = this.id;
    let votesReceived = 1; // Vote for self

    console.log(`Node ${this.id}: Starting election for term ${this.currentTerm}`);

    const votePromises = this.peers.map(async (peer) => {
      try {
        const response = await fetch(`${peer}/request-vote`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            term: this.currentTerm,
            candidateId: this.id,
            lastLogIndex: this.log.length - 1,
            lastLogTerm: this.log[this.log.length - 1]?.term || 0,
          }),
          signal: AbortSignal.timeout(1000),
        });
        return response.json();
      } catch {
        return { voteGranted: false };
      }
    });

    const results = await Promise.all(votePromises);
    votesReceived += results.filter(r => r.voteGranted).length;

    const majority = Math.floor((this.peers.length + 1) / 2) + 1;

    if (this.state === 'candidate' && votesReceived >= majority) {
      this.becomeLeader();
    } else {
      this.resetElectionTimer();
    }
  }

  becomeLeader() {
    this.state = 'leader';
    console.log(`Node ${this.id}: Became leader for term ${this.currentTerm}`);

    // Send periodic heartbeats
    this.heartbeatTimer = setInterval(
      () => this.sendHeartbeats(),
      this.heartbeatInterval
    );
  }

  async sendHeartbeats() {
    for (const peer of this.peers) {
      try {
        await fetch(`${peer}/append-entries`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            term: this.currentTerm,
            leaderId: this.id,
            entries: [],
            leaderCommit: this.commitIndex,
          }),
          signal: AbortSignal.timeout(500),
        });
      } catch {
        // Peer may be down
      }
    }
  }

  // Handle vote request
  handleVoteRequest({ term, candidateId, lastLogIndex, lastLogTerm }) {
    if (term > this.currentTerm) {
      this.currentTerm = term;
      this.state = 'follower';
      this.votedFor = null;
    }

    const voteGranted =
      term >= this.currentTerm &&
      (this.votedFor === null || this.votedFor === candidateId);

    if (voteGranted) {
      this.votedFor = candidateId;
      this.resetElectionTimer();
    }

    return { term: this.currentTerm, voteGranted };
  }

  // Handle heartbeat / log entries
  handleAppendEntries({ term, leaderId, entries }) {
    if (term >= this.currentTerm) {
      this.currentTerm = term;
      this.state = 'follower';
      this.resetElectionTimer();
    }

    return { term: this.currentTerm, success: term >= this.currentTerm };
  }
}
```

## Where Consensus is Used in Practice

```
┌────────────────────────────────────────────────────────┐
│ System           │ Consensus Used For                   │
├──────────────────┼──────────────────────────────────────┤
│ etcd             │ Key-value store (uses Raft)           │
│ ZooKeeper        │ Configuration, leader election (ZAB)  │
│ Consul           │ Service discovery (uses Raft)         │
│ Kafka            │ Controller election, ISR (uses Raft)  │
│ Redis Sentinel   │ Leader election (custom protocol)     │
│ CockroachDB      │ Distributed SQL (uses Raft)           │
│ MongoDB          │ Replica set election (custom Raft)    │
│ PostgreSQL       │ Patroni uses etcd/ZooKeeper/Consul    │
└────────────────────────────────────────────────────────┘
```

### Using etcd for Leader Election in Node.js

```javascript
import { Etcd3 } from 'etcd3';

const client = new Etcd3({ hosts: 'http://etcd:2379' });

class LeaderElection {
  constructor(client, electionName, instanceId) {
    this.client = client;
    this.electionName = electionName;
    this.instanceId = instanceId;
    this.isLeader = false;
  }

  async start() {
    const lease = this.client.lease(10); // 10 second TTL
    lease.on('lost', () => {
      this.isLeader = false;
      console.log('Lost leadership, re-electing...');
      this.start();
    });

    const key = `election/${this.electionName}`;

    try {
      // Try to become leader (atomic put-if-absent)
      await this.client.if(key, 'Create', '==', 0)
        .then(this.client.put(key).value(this.instanceId).lease(lease.grant))
        .commit();

      this.isLeader = true;
      console.log(`${this.instanceId}: I am the leader!`);
    } catch {
      // Someone else is leader — watch for changes
      this.isLeader = false;
      console.log(`${this.instanceId}: Following. Watching for leader change...`);

      const watcher = await this.client.watch().key(key).create();
      watcher.on('delete', () => {
        watcher.cancel();
        this.start(); // Re-try election
      });
    }
  }
}

// Usage
const election = new LeaderElection(client, 'scheduler', 'instance-1');
await election.start();

// Only leader runs scheduled tasks
if (election.isLeader) {
  runScheduledTasks();
}
```

## Paxos vs Raft

```
┌────────────────┬─────────────────────┬────────────────────┐
│                │ Paxos               │ Raft               │
├────────────────┼─────────────────────┼────────────────────┤
│ Understandable │ Notoriously hard    │ Designed to be     │
│                │                     │ understandable     │
├────────────────┼─────────────────────┼────────────────────┤
│ Leader         │ Multiple proposers  │ Single leader      │
│                │ (no fixed leader)   │                    │
├────────────────┼─────────────────────┼────────────────────┤
│ Phases         │ Prepare + Accept    │ Leader election +  │
│                │ (2 phases per value)│ Log replication    │
├────────────────┼─────────────────────┼────────────────────┤
│ Used in        │ Google Chubby       │ etcd, Consul,      │
│                │ (historical)        │ CockroachDB        │
└────────────────┴─────────────────────┴────────────────────┘
```

## Common Pitfalls

1. **Implementing your own consensus**: Use established implementations (etcd, ZooKeeper, Consul). Rolling your own is extremely error-prone.
2. **Not handling split brain**: If two nodes both think they are leader, data corruption can occur. Always verify leadership before performing leader-only operations.
3. **Network partition between minority and majority**: The minority partition cannot elect a leader (no majority). Ensure your cluster has an odd number of nodes.
4. **Not testing failure scenarios**: Consensus algorithms are only as good as their implementation. Test node crashes, network partitions, and slow nodes.

## Summary

Distributed consensus enables multiple nodes to agree on values, leader election, and state machine replication. Raft is the preferred algorithm for its understandability — it separates leader election from log replication and guarantees safety through term-based voting. In practice, use established consensus systems (etcd, Consul, ZooKeeper) rather than implementing your own. Consensus is the foundation of reliable distributed systems, from database replication to service discovery.

